  "characters": [
    {
      "name": "角色姓名",
      "gender": "男/女",
      "age": "具体年龄或年龄段",
      "role_type": "主角/配角/龙套",
      "appearance": {
        "hair": "发型和发色描述",
        "face": "脸型和五官特征",
        "body": "身材特征",
        "skin": "肤色"
      },
      "personality": "性格特点",
      "clothing_style": "服装风格"
    }
  ]
}
```
